raw:
[
  {
    "节": "②",
    "缺陷": "在利用数据进行特征筛选后划分训练测试集，导致数据泄露和模型评估过拟合。"
  },
  {
    "节": "④",
    "缺陷": "未进行多重比较校正（如Bonferroni校正），直接以P<0.05判定6次检验会导致极高的I类错误率。"
  },
  {
    "节": "⑤",
    "缺陷": "平均值（320 mg/L）远大于最大值描述（86 mg/L），数据严重自相矛盾。"
  }
]

[
  {
    "节": "⑤",
    "缺陷": "平均值（320 mg/L）远超浓度范围最大值（86 mg/L），数据严重自相矛盾。"
  }
]

[
  {"节": "②", "缺陷": "建模前基于全部240组数据筛选特征导致数据泄露，破坏了测试集的独立性"},
  {"节": "④", "缺陷": "对同一数据集进行6次两两t检验未进行多重比较校正，大幅增加了假阳性错误概率"},
  {"节": "⑤", "缺陷": "平均值(320)超出测量范围(0.5-86)且远大于中位数，数据描述自相矛盾"}
]

[
  {"节": "②", "缺陷": "建模前对全量数据标准化及特征筛选会导致数据泄露，违反模型评估独立性原则。"},
  {"节": "④", "缺陷": "直接进行6次两两t检验未作多重比较校正，会显著放大假阳性概率，统计方法不当。"},
  {"节": "⑤", "缺陷": "报告的平均值（320 mg/L）远超数据最大值（86 mg/L），数据自相矛盾，数学上不成立。"}
]

[
  {"节": "②", "缺陷": "建模前对全量数据标准化及特征筛选后再划分训练测试集，导致数据泄漏（Data Leakage）"},
  {"节": "④", "缺陷": "进行6组两两独立样本t检验未进行多重比较校正，统计推断不严谨且大幅增加假阳性风险"},
  {"节": "⑤", "缺陷": "平均值（320 mg/L）远超数据范围最大值（86 mg/L），存在明显的数学逻辑矛盾"}
]

[
  {
    "节": "④",
    "缺陷": "XGBoost基于树的模型输出的是不纯度减少或增益的相对比例总和为1，0.31的单一特征重要性与其余特征之和超过1或无法构成有效解释，且通常归一化后总和为1，此处表述违反特征重要性总和约束或存在统计逻辑错误。"
  },
  {
    "节": "⑥",
    "缺陷": "报告的平均含量（0.32 mg/kg）远低于仪器的检出限（5 mg/kg），表明数据完全处于检测盲区，平均值的计算与报告在科学上无效。"
  }
]

[
  {
    "节": "②",
    "缺陷": "使用包含目标变量（内梅罗指数由各金属单项指数计算得出）的特征构建模型，导致严重的目标泄露（数据 leakage）和逻辑循环。"
  },
  {
    "节": "⑥",
    "缺陷": "报告的平均含量（0.32 mg/kg）远低于仪器的检出限（5 mg/kg），表明测量数据无效或存在严重的逻辑矛盾。"
  }
]

[
  {"节": "②", "缺陷": "内梅罗综合污染指数由五种重金属实测浓度及单项污染指数直接计算得出，将其作为输入特征会导致严重的数据泄露。"},
  {"节": "④", "缺陷": "特征重要性无法直接推导因果关系，且模型预测目标为污染指数而非重金属浓度，不能据此说明重金属富集的驱动因素。"},
  {"节": "⑥", "缺陷": "报告的 Cd 平均含量 0.32 mg/kg 低于仪器检出限 5 mg/kg，存在数据自相矛盾和测量流程根本性错误。"}
]

[
  {"节": "②", "缺陷": "基于全体样本做特征选择后再划分训练集与测试集，造成数据泄露，测试集信息已污染特征筛选过程，评估结果不可信。"},
  {"节": "④", "缺陷": "对6组季节比较均使用独立样本t检验，但同一批样本在不同季节间存在配对/重复测量关系，且未做多重比较校正，统计方法选择错误。"},
  {"节": "⑤", "缺陷": "浓度范围0.5–86 mg/L与平均值320 mg/L自相矛盾，320超出最大值86，数据不可能成立。"}
]

[
  {"节": "②", "缺陷": "先基于全体样本做相关性筛选特征再划分训练集与测试集，导致测试集信息泄露到特征选择中，造成模型评估结果乐观偏倚。"},
  {"节": "④", "缺陷": "对6组两两比较均使用独立样本t检验而未做多重比较校正，膨胀I类错误率。"},
  {"节": "⑤", "缺陷": "平均值320 mg/L远超最大值86 mg/L，数据自相矛盾，统计量明显错误。"}
]

[
  {"节": "②", "缺陷": "以内梅罗综合污染指数为预测目标，但该指数由五种重金属的单项污染指数计算得到，而单项污染指数又直接由五种重金属实测浓度计算得到，输入特征中同时包含实测浓度与单项污染指数，构成严重的数据泄漏（data leakage），模型本质上是在学习一个确定性数学公式而非真实的环境驱动关系。"},
  {"节": "④", "缺陷": "特征重要性得分高仅说明该特征在模型预测中的贡献大，不能直接等同于该因素是重金属富集的主要驱动因素，混淆了统计相关性与因果机制。"},
  {"节": "⑥", "缺陷": "便携式XRF对Cd的检出限为5 mg/kg，但报告的平均含量为0.32 mg/kg，远低于检出限，说明绝大多数样本的Cd浓度为未检出（ND）值，该平均值在方法学上不可靠。"}
]

[
  {"节": "②", "缺陷": "内梅罗综合污染指数由单项污染指数计算得出，将其作为目标变量而将单项污染指数作为输入特征，导致数据泄露与模型逻辑循环。"},
  {"节": "⑥", "缺陷": "便携式XRF对Cd的检出限为5 mg/kg，报告的平均含量为0.32 mg/kg，远低于检出限，数据不可靠且违背检测常识。"}
]
